testbench:
`timescale 1ns/1ps
module tb;
  reg [7:0] a, b;
  wire [8:0] sum;

  add8 dut(.a(a), .b(b), .sum(sum));

  task check(input [7:0] ta, input [7:0] tb, input [8:0] expected);
    begin
      a = ta; b = tb; #1;
      if (sum !== expected) begin
        $display("FAIL a=%0d b=%0d expected=%0d got=%0d", ta, tb, expected, sum);
        $fatal(1);
      end
    end
  endtask

  initial begin
    check(8'd0, 8'd0, 9'd0);
    check(8'd3, 8'd5, 9'd8);
    check(8'd255, 8'd1, 9'd256);
    check(8'd127, 8'd128, 9'd255);
    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module add8(input [7:0] a, input [7:0] b, output [8:0] sum);
  assign sum = a + b;
endmodule
